class Solution {
public:
    int minimizeXor(int num1, int num2) {
        int setBits = __builtin_popcount(num2);
        int result = 0;
        for (int i = 30; i >= 0; --i) {
            if ((num1 >> i) & 1) {
                if (setBits > 0) {
                    result |= (1 << i);
                    --setBits;
                }
            } else if (setBits > 0) {
                result |= (1 << i);
                --setBits;
            }
        }
        return result;
    }
};
